749   KnownBits Res = KnownBits::computeForAddSub(Add, /*NSW=*/Signed,
750                                               /*NUW=*/!Signed, LHS, RHS);
751 
752   if (Overflow) {
753     // We know whether or not we overflowed.
754     if (!(*Overflow)) {
755       // No overflow.
756       return Res;
757     }
758 
759     // We overflowed
